// Obtenir la resposta de Pexels
const pexelsResponse = $input.item.json;
const photo = pexelsResponse.photos && pexelsResponse.photos[0];

// Obtenir la URL de la imatge
let imageUrl = 'https://images.pexels.com/photos/270632/pexels-photo-270632.jpeg?auto=compress&cs=tinysrgb&w=1200'; // Fallback

if (photo && photo.src) {
  // Utilitzar large2x per millor qualitat (1920x1080 o similar)
  imageUrl = photo.src.large2x || photo.src.large || photo.src.original;
  console.log(`Imatge trobada a Pexels: ${imageUrl}`);
} else {
  console.warn('No s\'ha trobat cap imatge a Pexels, utilitzant fallback');
}

// Obtenir els articles
const articles = $('Extract Articles').item.json.articles || [];

if (articles.length === 0) {
  throw new Error('No s\'han trobat articles per actualitzar');
}

// Actualitzar cada article amb la URL de la imatge
const updatedArticles = articles.map(article => {
  let markdown = article.markdown;

  // Actualitzar el frontmatter
  const frontmatterMatch = markdown.match(/^(---\n)([\s\S]*?)(\n---)/);

  if (!frontmatterMatch) {
    throw new Error(`L'article ${article.locale} no té frontmatter vàlid`);
  }

  const frontmatterStart = frontmatterMatch[1];
  let frontmatter = frontmatterMatch[2];
  const frontmatterEnd = frontmatterMatch[3];

  // Reemplaçar o afegir el camp image
  if (frontmatter.match(/^image:\s*["'][^"']+["']/m)) {
    frontmatter = frontmatter.replace(
      /^image:\s*["'][^"']+["']/m,
      `image: "${imageUrl}"`
    );
  } else {
    const dateMatch = frontmatter.match(/^(date:\s*["'][^"']+["'])/m);
    if (dateMatch) {
      frontmatter = frontmatter.replace(
        /^(date:\s*["'][^"']+["'])/m,
        `$1\nimage: "${imageUrl}"`

      );
    } else {
      frontmatter = `${frontmatter}\nimage: "${imageUrl}"`;
    }
  }

  const updatedMarkdown = `${frontmatterStart}${frontmatter}${frontmatterEnd}${markdown.substring(frontmatterMatch[0].length)}`;

  return {
    ...article,
    markdown: updatedMarkdown
  };
});

return {
  json: {
    articles: updatedArticles,
    slug: $('Extract Articles').item.json.slug,
    title: $('Extract Articles').item.json.title,
    imageUrl: imageUrl
  }
};

// Codi simplificat per processar resposta JSON de Gemini
// Aquest codi és molt més simple i robust que parsejar markdown

let response = '';

// Obtenir el text de la resposta
if ($input.item.json.content && $input.item.json.content.parts && $input.item.json.content.parts[0]) {
  response = $input.item.json.content.parts[0].text || '';
} else if ($input.item.json.message) {
  response = $input.item.json.message;
} else if ($input.item.json.text) {
  response = $input.item.json.text;
} else if (typeof $input.item.json.content === 'string') {
  response = $input.item.json.content;
}

console.log('Response length:', response.length);

if (!response || response.length === 0) {
  throw new Error('No s\'ha rebut cap resposta de Gemini');
}

// Netejar la resposta per eliminar possibles code blocks markdown
// Si Gemini retorna el JSON dins d'un code block, extreure'l
let jsonString = response.trim();

// Eliminar code blocks markdown si n'hi ha
if (jsonString.startsWith('```')) {
  // Eliminar el primer ``` i el tipus si existeix
  jsonString = jsonString.replace(/^```(?:json)?\n?/, '');
  // Eliminar el ``` final
  jsonString = jsonString.replace(/\n?```$/, '');
  jsonString = jsonString.trim();
}

// Escapar caràcters de control dins de strings JSON (Gemini pot retornar \n literals)
function escapeControlCharsInJsonStrings(str) {
  let result = '';
  let inString = false;
  let escapeNext = false;
  for (let i = 0; i < str.length; i++) {
    const c = str[i];
    if (escapeNext) {
      result += c;
      escapeNext = false;
      continue;
    }
    if (c === '\\' && inString) {
      result += c;
      escapeNext = true;
      continue;
    }
    if (c === '"') {
      inString = !inString;
      result += c;
      continue;
    }
    if (inString && (c === '\n' || c === '\r' || c === '\t')) {
      if (c === '\n') result += '\\n';
      else if (c === '\r') result += '\\r';
      else if (c === '\t') result += '\\t';
      continue;
    }
    result += c;
  }
  return result;
}
jsonString = escapeControlCharsInJsonStrings(jsonString);

// Intentar parsejar el JSON
let data;
try {
  data = JSON.parse(jsonString);
} catch (error) {
  console.error('Error parsejant JSON:', error.message);
  console.log('Primers 500 caràcters de la resposta:', jsonString.substring(0, 500));
  throw new Error(`Error parsejant la resposta JSON: ${error.message}`);
}

// Verificar l'estructura
if (!data.articles || !Array.isArray(data.articles)) {
  throw new Error('La resposta JSON no conté un array "articles"');
}

if (data.articles.length !== 3) {
  throw new Error(`S\'esperaven 3 articles però s\'han trobat ${data.articles.length}`);
}

// Processar cada article
const articles = [];
const slug = data.slug || 'untitled-post';

for (const article of data.articles) {
  // Verificar camps obligatoris
  if (!article.locale) {
    throw new Error('Un article no té camp "locale"');
  }

  if (!article.content) {
    throw new Error(`L'article ${article.locale} no té camp "content"`);
  }

  // Verificar que el locale és vàlid
  const validLocales = ['en', 'ca', 'es'];
  if (!validLocales.includes(article.locale)) {
    throw new Error(`Locale invàlid: ${article.locale}. Ha de ser un de: ${validLocales.join(', ')}`);
  }

  // Extreure el títol del frontmatter si no està al nivell superior
  let title = article.title;
  if (!title && article.content) {
    const titleMatch = article.content.match(/title:\s*["']([^"']+)["']/);
    if (titleMatch) {
      title = titleMatch[1];
    }
  }

  // Generar el markdown final
  // Si el content ja inclou el frontmatter, usar-lo directament
  // Sinó, construir-lo
  let markdown = article.content;

  // Verificar si el content ja té frontmatter
  if (!markdown.match(/^---\n/)) {
    // Construir el frontmatter
    const frontmatter = `---\ntitle: "${article.title || title || 'Untitled'}"\ndescription: "${article.description || ''}"\ndate: "${article.date || '2025-11-22'}"\nimage: "/blog/placeholder.png"\n---`;
    markdown = `${frontmatter}\n\n${article.content}`;
  }

  articles.push({
    locale: article.locale,
    markdown: markdown,
    slug: slug,
    title: title || article.title || 'Untitled',
    filename: `${slug}-${article.locale}.md`
  });
}

// Verificar que tenim els 3 idiomes
const locales = articles.map(a => a.locale);
if (!locales.includes('en')) {
  throw new Error('Falta l\'article en anglès');
}
if (!locales.includes('ca')) {
  throw new Error('Falta l\'article en català');
}
if (!locales.includes('es')) {
  throw new Error('Falta l\'article en espanyol');
}

// Assegurar que tots els articles tenen el mateix slug
articles.forEach(article => {
  article.slug = slug;
});

const enArticle = articles.find(a => a.locale === 'en');
const mainTitle = enArticle ? enArticle.title : data.topic || 'Blog Post';

console.log(`Articles processats: ${articles.length}`);
console.log(`Slug: ${slug}`);
console.log(`Títol: ${mainTitle}`);

return {
  json: {
    articles: articles,
    slug: slug,
    title: mainTitle,
    count: articles.length,
    locales: locales,
    topic: data.topic || '',
    justification: data.justification || ''
  }
};

const articles = $input.item.json.articles || [];
const slug = $input.item.json.slug;
const title = $input.item.json.title;
const imageUrl = $input.item.json.imageUrl;

if (articles.length !== 3) {
  throw new Error(`S'esperaven 3 articles però s'han trobat ${articles.length}`);
}

// Crear 3 items separats (un per cada idioma)
return articles.map(article => {
  const localeNames = {
    'en': 'EN',
    'ca': 'CA',
    'es': 'ES'
  };

  return {
    json: {
      locale: article.locale,
      markdown: article.markdown,
      slug: slug,
      title: article.title,
      imageUrl: imageUrl,
      filePath: `content/blog/${article.locale}/${slug}.md`,
      commitMessage: `Add blog post: ${title} (${localeNames[article.locale] || article.locale.toUpperCase()})`
    }
  };
});
